import './App.css';
import React, {useEffect, useState} from "react";
import Axios from "axios";
import "./styles.css";
import 'react-edit-text/dist/index.css';

function App() {
    const [listOfPaintings, setListOfPaintings] = useState([]);
    const [title, setTitle] = useState("");
    const [artist, setArtist] = useState("");
    const [movement, setMovement] = useState(" ");
    const [year, setYear] = useState(0);
    const [color, setColor] = useState("#000000");

    async function fetchData() {
        const response = await Axios.get(process.env.REACT_APP_HOST_LINK + "/getPaintings");
        setListOfPaintings(response.data)
    }

    useEffect(() => {
        fetchData();
    }, []);


    const createPainting = () => {
        console.log(title, artist, movement, year, color)
        if (title === "") {
            alert("Please enter a title.")
        } else if (artist === "") {
            alert("Please enter an artist.")
        }
        Axios.post(process.env.REACT_APP_HOST_LINK + "/createPainting", {
            title, artist, movement, year, color
        }).then(() => {
            fetchData();
        });
    };


    const deletePainting = (id) => {
        Axios.delete(`http://localhost:3000/deletePainting/${id}`)
            .then((id) => {
                console.log(id);
                fetchData();
            });
    };

    const clearPaintings = () => {
        Axios.delete("http://localhost:3000/clearPaintings/")
            .then((response) => {
                console.log(response);
                fetchData();
            });
    };

    const updatePainting = (id, newTitle, newArtist, newMovement, newYear, newColor) => {
        newTitle = newTitle || undefined;
        newArtist = newArtist || undefined;
        newMovement = newMovement || undefined;
        Axios.put("http://localhost:3000/updatePainting/", {
            id: id, title: newTitle, artist: newArtist, movement: newMovement, year: parseInt(newYear), color: newColor
        })
            .then((response) => {
                console.log(response);
                fetchData();
            });
    };



    return (
        <div className="App">
            <input
                style={{ width: "30px", height: "22px",}}
                type="color"
                placeholder="Hex Color"
                onChange={(event) => {
                    setColor(event.target.value);
                }}
            />
        <div className="paintingsDisplay">
            {listOfPaintings.map((painting) => {
                return (<div className="cssPaintings">
                    <h1 className="cssTitle"
                        style={{backgroundColor: painting.color}}> {painting.title}</h1>
                    <h1 className="cssArtist"
                        style={{backgroundColor: painting.color}}>{painting.artist}</h1>
                    <h1 className="cssYear"
                        style={{backgroundColor: painting.color}}>{painting.year}</h1>
                    <h1 className="cssMovement"
                        style={{backgroundColor: painting.color}}>{painting.movement}</h1>
                    <button onClick={() => {
                        const newTitle = prompt('Input text to change the title.');
                        const newArtist = prompt('Input text to change the artist.');
                        const newYear = prompt('Input a number to change the year.');
                        const newMovement = prompt('Input text to change the movement.');
                        if (newArtist || newTitle ||newMovement || newYear || newMovement) {
                            updatePainting(painting._id, newTitle, newArtist, newMovement, newYear)
                        } else {
                            alert("Please enter something.")
                        }
                    }}> Update
                    </button>
                    <button onClick={() => {
                        if (window.confirm('Delete?')) {
                            deletePainting(painting._id)
                        }
                    }}> Delete
                    </button>
                </div>)

            })}

        </div>
        <div>
            <input
                style={{ width: "200px",}}
                type="text"
                placeholder="Title"
                onChange={(event) => {
                    setTitle(event.target.value);
                }}
            />
            <input
                style={{ width: "135px",}}
                type="text"
                placeholder="Artist"
                onChange={(event) => {
                    setArtist(event.target.value);
                }}
            />
            <input
                style={{ width: "65px",}}
                type="number"
                placeholder="Year"
                onChange={(event) => {
                    setYear(event.target.value);
                }}
            />
            <input
                style={{ width: "100px",}}
                type="text"
                placeholder="Movement"
                onChange={(event) => {
                    setMovement(event.target.value);
                }}
            />
            <input
                style={{ width: "30px", height: "22px",}}
                type="color"
                placeholder="Hex Color"
                onChange={(event) => {
                    setColor(event.target.value);
                }}
            />
            <button onClick={createPainting}> Log Painting</button>
            <button onClick={() => {
                if (window.confirm('Clear?')) {
                    clearPaintings();
                }
            }}> Clear Paintings
            </button>
        </div>
    </div>);

}

export default App;
